import{_ as t,o as a,c as o,a0 as p}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"NUC显卡驱动问题","description":"","frontmatter":{"title":"NUC显卡驱动问题","date":"2016-06-22T22:11:15.000Z","category":"Linux","tags":["Linux","驱动","Ubuntu"]},"headers":[],"relativePath":"posts/NUC显卡驱动问题.md","filePath":"posts/NUC显卡驱动问题.md","lastUpdated":1783008259000}'),n={name:"posts/NUC显卡驱动问题.md"};function s(r,e,i,c,d,l){return a(),o("div",null,[...e[0]||(e[0]=[p(`<p>买了新的NUC装老的Linux系统会感觉很蛋疼，显卡太新了。</p><p>比如Intel NUC5i7RYH，安装Ubuntu 16.04一点问题都没有，各种功能也都OK，但这毕竟是新出的系统，很多软件支持都还没跟上，比如OpenBTS、OpenLTE这些，编译时候多多少少会有点问题，虽然这些都能解决，但更多人还是更习惯用Ubuntu 14.04，安装时候会发现，系统无法启动，到了图形界面就ByeBye了，即使从别的机器上将Ub1404移植过来，启动依旧会报错。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/NUC%E6%98%BE%E5%8D%A1%E9%A9%B1%E5%8A%A8%E9%97%AE%E9%A2%98.md/1591024432777.jpg" alt=""></p><p>这时候怎么办呢？这个问题其实不是内核的驱动不支持，而是Xorg的intel驱动版本不支持，只要更新到最新版本就行。</p><h2 id="_1、全新安装" tabindex="-1">1、全新安装 <a class="header-anchor" href="#_1、全新安装" aria-label="Permalink to &quot;1、全新安装&quot;">​</a></h2><p>如果机器还没安装系统，或者打算全新安装，直接安装Ubuntu 14.04 Server版本，安装字符界面的Ubuntu，再用下面的命令升级然后安装图形界面即可：</p><p><strong>apt-get update apt-get upgrade apt-get dist-upgrade</strong></p><p>更新完成后，安装图形界面</p><p><strong>apt-get install ubuntu-desktop</strong></p><p>Server版本的内核版本新，软件包也新，<code>upgrade</code>后，支持木问题。</p><h2 id="_2、字符界面升级" tabindex="-1">2、字符界面升级 <a class="header-anchor" href="#_2、字符界面升级" aria-label="Permalink to &quot;2、字符界面升级&quot;">​</a></h2><p>如果已经装了Ubuntu 14.04，但是系统无法启动，图形界面启动报错，怎么办呢？</p><p>在<code>Grub</code>界面按<code>e</code>编辑，在<code>vmlinuz</code>那一行<code>ro</code>后面加上<code>text</code>参数，从字符启动，然后用<code>方法1</code>的前3条命令<code>upgrade</code>一下就行了。</p><p>或者在图形界面启动失败的情况下，用<code>Ctrl+Alt+F2</code>切换到其他控制台，再用<code>方法1</code>的命令升级。</p><p>如果遇到了循环登录的问题，参照我的另一篇Blog<a href="http://blog.white-alone.com/Ubuntu%E5%BE%AA%E7%8E%AF%E7%99%BB%E5%BD%95%E9%97%AE%E9%A2%98" target="_blank" rel="noreferrer">《Ubuntu循环登录问题》</a></p><h2 id="_3、驱动升级" tabindex="-1">3、驱动升级 <a class="header-anchor" href="#_3、驱动升级" aria-label="Permalink to &quot;3、驱动升级&quot;">​</a></h2><p>这个方法可行性不高，前面两个方法基本就OK了。</p><p>有老外做了一个新的驱动，<a href="https://launchpad.net/~oibaf/+archive/ubuntu/graphics-drivers" target="_blank" rel="noreferrer">PPA</a></p><p><strong>add-apt-repository ppa:oibaf/graphics-drivers apt-get update</strong></p><p>安装新的驱动，然后添加<code>Xorg</code>配置文件</p><p><strong>vi /etc/X11/xorg.conf</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Section &quot;Device&quot;</span></span>
<span class="line"><span> Identifier &quot;Device0&quot;</span></span>
<span class="line"><span> Driver &quot;intel&quot;</span></span>
<span class="line"><span> VendorName &quot;INTEL Corporation&quot;</span></span>
<span class="line"><span> Option &quot;TearFree&quot; &quot;true&quot;</span></span>
<span class="line"><span>EndSection</span></span></code></pre></div><p>然后重启就行</p><h2 id="_4、建议" tabindex="-1">4、建议 <a class="header-anchor" href="#_4、建议" aria-label="Permalink to &quot;4、建议&quot;">​</a></h2><p>Server版本用的内核比Desktop版本的内核版本要高，建议从Sever字符界面开始扩展，当年安装系统都是从字符界面的最小系统开始安装，这样不会装一堆乱七八糟的东东，而且系统资源占用少。</p><p>另外，图形界面可以只装<code>gnome-session</code>，也可以装KDE或者其他图形界面。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/NUC%E6%98%BE%E5%8D%A1%E9%A9%B1%E5%8A%A8%E9%97%AE%E9%A2%98.md/1591024432780.jpg" alt=""></p>`,27)])])}const h=t(n,[["render",s]]);export{g as __pageData,h as default};
